class StockSpanner {
public:
    StockSpanner() {

    }
    stack<int> indices;
    stack<int> numbers;
    int next(int price) {
        if(indices.empty()){
            indices.push(price);
            numbers.push(1);
            return 1;
        }
        int temp = 1;
        while(indices.top() < price){
            temp += numbers.top();
            indices.pop();
            numbers.pop();
        }
        indices.push(price);
        numbers.push(temp);
        return temp;
    }
};

